// src/audit/audit.outbox.service.spec.ts
import { Test, TestingModule } from '@nestjs/testing';
import { Logger } from '@nestjs/common';
import { AuditOutboxService } from './audit.outbox.service';
import { PrismaService } from '../prisma/prisma.service';
import { AuditOutboxStatus, Prisma } from '@prisma/client';

describe('AuditOutboxService', () => {
  let service: AuditOutboxService;
  let prisma: {
    auditOutbox: {
      findMany: jest.Mock;
      update: jest.Mock;
    };
    auditLog: {
      create: jest.Mock;
    };
    $transaction: jest.Mock;
  };

  const mockLogger = {
    error: jest.fn(),
    log: jest.fn(),
    warn: jest.fn(),
    debug: jest.fn(),
  };

  const mockOutboxItem = {
    id: BigInt(1),
    payload: {
      entityType: 'User',
      entityId: '123',
      action: 'CREATE',
    },
    status: AuditOutboxStatus.PENDING,
    attempts: 0,
    lastError: null,
    createdAt: new Date(),
  };

  beforeEach(async () => {
    prisma = {
      auditOutbox: {
        findMany: jest.fn(),
        update: jest.fn(),
      },
      auditLog: {
        create: jest.fn(),
      },
      $transaction: jest.fn((callback) => callback(prisma)),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AuditOutboxService,
        {
          provide: PrismaService,
          useValue: prisma,
        },
      ],
    }).compile();

    service = module.get<AuditOutboxService>(AuditOutboxService);

    jest.spyOn(Logger.prototype, 'error').mockImplementation(mockLogger.error);
    jest.spyOn(Logger.prototype, 'log').mockImplementation(mockLogger.log);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('processBatch', () => {
    it('should process pending items in a transaction', async () => {
      prisma.auditOutbox.findMany.mockResolvedValue([mockOutboxItem]);
      prisma.auditLog.create.mockResolvedValue({ id: BigInt(1) });
      prisma.auditOutbox.update.mockResolvedValue({});

      await service.processBatch(100);

      expect(prisma.$transaction).toHaveBeenCalled();
      expect(prisma.auditLog.create).toHaveBeenCalledWith({
        data: mockOutboxItem.payload,
      });
      expect(prisma.auditOutbox.update).toHaveBeenCalledWith({
        where: { id: mockOutboxItem.id },
        data: {
          status: AuditOutboxStatus.PROCESSED,
          processedAt: expect.any(Date),
        },
      });
    });

    it('should use custom batch size', async () => {
      prisma.auditOutbox.findMany.mockResolvedValue([]);

      await service.processBatch(50);

      expect(prisma.auditOutbox.findMany).toHaveBeenCalledWith({
        where: { status: AuditOutboxStatus.PENDING },
        take: 50,
        orderBy: { createdAt: 'asc' },
      });
    });

    it('should return early when no pending items', async () => {
      prisma.auditOutbox.findMany.mockResolvedValue([]);

      await service.processBatch();

      expect(prisma.$transaction).not.toHaveBeenCalled();
    });

    it('should handle transaction failures gracefully', async () => {
      const failingTx = jest.fn().mockRejectedValue(new Error('Transaction error'));
      prisma.$transaction = failingTx;
      prisma.auditOutbox.findMany.mockResolvedValue([mockOutboxItem]);

      await service.processBatch();

      expect(mockLogger.error).toHaveBeenCalledWith(
        expect.stringContaining('Failed to process audit outbox item'),
        expect.any(Error),
      );
      expect(prisma.auditOutbox.update).toHaveBeenCalledWith({
        where: { id: mockOutboxItem.id },
        data: {
          status: AuditOutboxStatus.FAILED,
          attempts: 1,
          lastError: expect.any(String),
        },
      });
    });

    it('should increment attempts on failure', async () => {
      prisma.auditOutbox.findMany.mockResolvedValue([
        { ...mockOutboxItem, attempts: 2 },
      ]);
      
      const failingTx = jest.fn().mockRejectedValue(new Error('Transaction error'));
      prisma.$transaction = failingTx;

      await service.processBatch();

      expect(prisma.auditOutbox.update).toHaveBeenCalledWith({
        where: { id: mockOutboxItem.id },
        data: {
          status: AuditOutboxStatus.FAILED,
          attempts: 3,
          lastError: expect.any(String),
        },
      });
    });

    it('should process multiple items', async () => {
      const items = [
        mockOutboxItem,
        { ...mockOutboxItem, id: BigInt(2) },
        { ...mockOutboxItem, id: BigInt(3) },
      ];
      prisma.auditOutbox.findMany.mockResolvedValue(items);
      prisma.auditLog.create.mockResolvedValue({ id: BigInt(1) });
      prisma.auditOutbox.update.mockResolvedValue({});

      await service.processBatch();

      expect(prisma.auditLog.create).toHaveBeenCalledTimes(3);
      expect(prisma.auditOutbox.update).toHaveBeenCalledTimes(3);
    });

    it('should log error message on failure', async () => {
      prisma.auditOutbox.findMany.mockResolvedValue([mockOutboxItem]);
      
      const failingTx = jest.fn().mockRejectedValue(new Error('Database connection failed'));
      prisma.$transaction = failingTx;

      await service.processBatch();

      expect(mockLogger.error).toHaveBeenCalledWith(
        'Failed to process audit outbox item 1:',
        expect.any(Error),
      );
    });
  });
});
